const response = $.steps.scrapeNews.response || {};
const data = response.data || response;
const markdown = (data.markdown || data.content || data.text || '').slice(0, 15000);
const title = data.title || data.metadata?.title || '';
return { markdown, title, url: $.input.newsUrl, contentLength: markdown.length };

const d = $.steps.extractContent.output;
const max = $.input.maxArticles || 10;
let prompt = 'You are a news analyst. Extract and summarize individual articles from the following scraped news site content.

';
prompt += 'SOURCE: ' + d.url + '
';
prompt += 'SITE TITLE: ' + d.title + '

';
prompt += 'SCRAPED CONTENT:
' + d.markdown + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Identify up to ' + max + ' distinct articles/posts
';
prompt += '- For each, extract: title, summary (2-3 sentences), category, key topics
';
prompt += '- Sort by relevance/importance

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "articles": [{
';
prompt += '    "title": "article title",
';
prompt += '    "summary": "2-3 sentence summary",
';
prompt += '    "category": "tech|business|science|politics|other",
';
prompt += '    "topics": ["topic1", "topic2"],
';
prompt += '    "importance": "high|medium|low"
';
prompt += '  }],
';
prompt += '  "siteSummary": "overall site digest in 2-3 sentences",
';
prompt += '  "totalArticles": 0
';
prompt += '}';
return { prompt };

let raw = $.steps.aiSummarize.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { articles: [], siteSummary: raw, totalArticles: 0 }; }

const ai = $.steps.parseAI.output;
const articles = ai.articles || [];
const today = new Date().toISOString().slice(0, 10);
let content = 'News Digest - ' + today + '\n\n';
content += 'Source: ' + $.input.newsUrl + '\n';
content += 'Summary: ' + (ai.siteSummary || '') + '\n\n';
articles.forEach((a, i) => {
  content += '## ' + (i + 1) + '. ' + (a.title || 'Untitled') + '\n';
  content += 'Category: ' + (a.category || 'other') + ' | Importance: ' + (a.importance || 'medium') + '\n';
  content += (a.summary || '') + '\n';
  content += 'Topics: ' + (a.topics || []).join(', ') + '\n\n';
});
return { title: 'News Digest - ' + $.input.newsUrl + ' - ' + today, content: content.slice(0, 1900), articleCount: articles.length };

const ai = $.steps.parseAI.output;
const articles = ai.articles || [];

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'News Digest', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Source:* <' + $.input.newsUrl + '|' + $.input.newsUrl + '>\n*' + articles.length + ' articles* summarized' } });

if (ai.siteSummary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ai.siteSummary.slice(0, 500) } });
}

blocks.push({ type: 'divider' });
articles.slice(0, 5).forEach(a => {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + (a.title || 'Untitled') + '* (' + (a.importance || 'medium') + ')\n' + (a.summary || '').slice(0, 200) } });
});

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Saved to Notion | Powered by Firecrawl + Claude AI' }] });

const fallback = 'News Digest: ' + articles.length + ' articles from ' + $.input.newsUrl;
return { blocks, fallback };
